export function jsonError(status, code) {
  return { status, body: { error: code } };
}

export function requireTenantAdmin(session) {
  if (!session?.roles?.includes("admin")) {
    return { ok: false, status: 403 };
  }

  return { ok: true, tenantId: session.tenantId };
}

import assert from "node:assert/strict";
import test from "node:test";

import { requireTenantAdmin } from "../src/auth.mjs";

test("takes the tenant from the authenticated session", () => {
  assert.deepEqual(
    requireTenantAdmin({ tenantId: "tenant-a", roles: ["admin"] }),
    { ok: true, tenantId: "tenant-a" },
  );
});

import { requireTenantAdmin } from "../auth.mjs";
import { jsonError } from "../http-response.mjs";

export async function listAuditRoute(request) {
  const auth = requireTenantAdmin(request.session);
  if (!auth.ok) return jsonError(auth.status, "forbidden");

  return { status: 501, body: { error: "not-implemented" } };
}
